noncompliant_code:
function handleSubmit(form) {
  // 60+ lines of validation, API calls,
  // DOM updates, error handling, and analytics
  // all interleaved in one function
}

compliant_code:
function handleSubmit(form) {
  const data = validateForm(form);
  const result = await submitToAPI(data);
  updateUI(result);
  trackEvent('form_submitted');
}
